import { useEffect, useState } from 'react';
import { BrowserRouter, Navigate, Route, Routes, useNavigate } from 'react-router-dom';
import { CssBaseline, ThemeProvider } from '@mui/material';
import { lightTheme, darkTheme } from './theme';
import LandingPage from './pages/LandingPage';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import SignupPage from './pages/SignupPage';
import ForgotPasswordPage from './pages/ForgotPasswordPage';
import { apiFetch } from './lib/api';

const SESSION_STORAGE_KEY = 'lanzo-session';

function loadSession() {
  const storedValue = localStorage.getItem(SESSION_STORAGE_KEY);

  if (!storedValue) {
    return { token: '', user: null };
  }

  try {
    return JSON.parse(storedValue);
  } catch (error) {
    localStorage.removeItem(SESSION_STORAGE_KEY);
    return { token: '', user: null };
  }
}

function saveSession(session) {
  localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(session));
}

function clearSession() {
  localStorage.removeItem(SESSION_STORAGE_KEY);
}

function AppRoutes({ isDark, onToggleTheme }) {
  const navigate = useNavigate();
  const [session, setSession] = useState(() => loadSession());

  useEffect(() => {
    if (!session.token) {
      return;
    }

    apiFetch('/auth/me', { token: session.token })
      .then((data) => {
        setSession((currentSession) => {
          const nextSession = { ...currentSession, user: data.user };
          saveSession(nextSession);
          return nextSession;
        });
      })
      .catch(() => {
        setSession({ token: '', user: null });
        clearSession();
      });
  }, [session.token]);

  const handleAuthenticated = (data) => {
    const nextSession = {
      token: data.token,
      user: data.user,
    };
    setSession(nextSession);
    saveSession(nextSession);
  };

  const handleLogin = async ({ email, password }) => {
    const data = await apiFetch('/auth/login', {
      method: 'POST',
      body: { email, password },
    });
    handleAuthenticated(data);
    return data;
  };

  const handleStartSignup = async (email) => {
    const data = await apiFetch('/auth/check-email', {
      method: 'POST',
      body: { email },
    });

    if (data.exists) {
      navigate(`/login?email=${encodeURIComponent(data.email)}&exists=1`);
      return data;
    }

    navigate(`/signup?email=${encodeURIComponent(data.email)}`);
    return data;
  };

  const handleLogout = () => {
    setSession({ token: '', user: null });
    clearSession();
    navigate('/login', { replace: true });
  };

  return (
    <Routes>
      <Route path="/" element={<LandingPage onStartSignup={handleStartSignup} />} />
      <Route
        path="/login"
        element={session.token ? <Navigate to="/app" replace /> : <LoginPage onLogin={handleLogin} />}
      />
      <Route
        path="/signup"
        element={
          session.token ? <Navigate to="/app" replace /> : <SignupPage onAuthenticated={handleAuthenticated} />
        }
      />
      <Route
        path="/forgot-password"
        element={
          session.token ? (
            <Navigate to="/app" replace />
          ) : (
            <ForgotPasswordPage onAuthenticated={handleAuthenticated} />
          )
        }
      />
      <Route
        path="/app"
        element={
          session.token ? (
            <HomePage
              token={session.token}
              user={session.user}
              isDark={isDark}
              onToggleTheme={onToggleTheme}
              onLogout={handleLogout}
            />
          ) : (
            <Navigate to="/login" replace />
          )
        }
      />
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

function App() {
  const [isDark, setIsDark] = useState(false);

  return (
    <ThemeProvider theme={isDark ? darkTheme : lightTheme}>
      <CssBaseline />
      <BrowserRouter>
        <AppRoutes isDark={isDark} onToggleTheme={() => setIsDark((value) => !value)} />
      </BrowserRouter>
    </ThemeProvider>
  );
}

export default App;