import { useMemo, useState } from 'react';
import {
  Alert,
  Box,
  Button,
  Stack,
  TextField,
} from '@mui/material';
import { useNavigate, useSearchParams } from 'react-router-dom';
import AuthShell from '../components/AuthShell';
import PasswordChecklist from '../components/PasswordChecklist';
import { apiFetch } from '../lib/api';
import { validatePassword } from '../lib/validators';

export default function SignupPage({ onAuthenticated }) {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const email = useMemo(() => searchParams.get('email') || '', [searchParams]);
  const [otp, setOtp] = useState('');
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [ticket, setTicket] = useState('');
  const [stage, setStage] = useState('otp');
  const [error, setError] = useState('');
  const [info, setInfo] = useState(email ? 'We sent a 6-digit OTP to your email.' : 'Enter your email on the landing page to start sign up.');
  const [submitting, setSubmitting] = useState(false);

  const handleVerifyOtp = async (event) => {
    event.preventDefault();

    if (!otp || otp.length !== 6) {
      setError('Enter the 6-digit OTP');
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      const data = await apiFetch('/auth/verify-otp', {
        method: 'POST',
        body: { email, otp, purpose: 'signup' },
      });

      setTicket(data.ticket);
      setStage('details');
      setInfo('OTP verified. Finish setting up your account.');
    } catch (verifyError) {
      setError(verifyError.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleRegister = async (event) => {
    event.preventDefault();

    if (!name.trim()) {
      setError('Name is required');
      return;
    }

    const passwordIssue = validatePassword(password);

    if (passwordIssue) {
      setError(passwordIssue);
      return;
    }

    if (password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      const data = await apiFetch('/auth/register', {
        method: 'POST',
        body: { email, name, password, ticket },
      });

      onAuthenticated(data);
      navigate('/app', { replace: true });
    } catch (registerError) {
      setError(registerError.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleResendOtp = async () => {
    try {
      setSubmitting(true);
      setError('');
      await apiFetch('/auth/check-email', {
        method: 'POST',
        body: { email },
      });
      setInfo('A fresh OTP has been sent to your email.');
    } catch (resendError) {
      setError(resendError.message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <AuthShell
      eyebrow="Finish sign up"
      title="Secure your workspace before the first task lands."
      description="We verify your email first, then collect your display name and password."
      cardTitle={stage === 'otp' ? 'Verify your email' : 'Create your account'}
      cardDescription={info}
      actionLabel="Log in"
      actionTo={email ? `/login?email=${encodeURIComponent(email)}` : '/login'}
    >
      {!email ? (
        <Stack spacing={2}>
          <Alert severity="info">Start from the landing page so Lanzo can send your OTP first.</Alert>
          <Button variant="contained" onClick={() => navigate('/', { replace: true })}>
            Go to landing page
          </Button>
        </Stack>
      ) : (
        <Box component="form" onSubmit={stage === 'otp' ? handleVerifyOtp : handleRegister}>
          <Stack spacing={2.25}>
            {error ? <Alert severity="error">{error}</Alert> : null}

            <TextField
              label="Email"
              value={email}
              name="email"
              autoComplete="username"
              fullWidth
              InputProps={{ readOnly: true }}
            />

            {stage === 'otp' ? (
              <>
                <TextField
                  label="OTP"
                  value={otp}
                  onChange={(event) => setOtp(event.target.value.replace(/\D/g, '').slice(0, 6))}
                  inputProps={{ inputMode: 'numeric', pattern: '[0-9]*', maxLength: 6 }}
                  fullWidth
                />

                <Button type="submit" variant="contained" size="large" disabled={submitting} fullWidth>
                  {submitting ? 'Verifying...' : 'Verify OTP'}
                </Button>

                <Button variant="text" onClick={handleResendOtp} disabled={submitting}>
                  Resend OTP
                </Button>
              </>
            ) : (
              <>
                <TextField
                  label="Name"
                  name="name"
                  value={name}
                  onChange={(event) => setName(event.target.value)}
                  autoComplete="name"
                  fullWidth
                />

                <TextField
                  label="Password"
                  name="password"
                  type="password"
                  value={password}
                  onChange={(event) => setPassword(event.target.value)}
                  autoComplete="new-password"
                  fullWidth
                />

                <PasswordChecklist password={password} />

                <TextField
                  label="Confirm password"
                  name="confirmPassword"
                  type="password"
                  value={confirmPassword}
                  onChange={(event) => setConfirmPassword(event.target.value)}
                  autoComplete="new-password"
                  fullWidth
                />

                <Button type="submit" variant="contained" size="large" disabled={submitting} fullWidth>
                  {submitting ? 'Creating account...' : 'Create account'}
                </Button>
              </>
            )}
          </Stack>
        </Box>
      )}
    </AuthShell>
  );
}