import { Stack, Typography } from '@mui/material';
import CheckCircleRoundedIcon from '@mui/icons-material/CheckCircleRounded';
import RadioButtonUncheckedRoundedIcon from '@mui/icons-material/RadioButtonUncheckedRounded';
import { getPasswordChecks } from '../lib/validators';

export default function PasswordChecklist({ password }) {
  const checks = getPasswordChecks(password);

  return (
    <Stack spacing={1} sx={{ mt: 1.5 }}>
      {checks.map((check) => {
        const Icon = check.valid ? CheckCircleRoundedIcon : RadioButtonUncheckedRoundedIcon;

        return (
          <Stack key={check.label} direction="row" spacing={1} alignItems="center">
            <Icon
              sx={{
                fontSize: 18,
                color: check.valid ? 'success.main' : 'text.disabled',
              }}
            />
            <Typography
              variant="body2"
              sx={{ color: check.valid ? 'text.primary' : 'text.secondary' }}
            >
              {check.label}
            </Typography>
          </Stack>
        );
      })}
    </Stack>
  );
}