import { useEffect, useState } from 'react';
import {
  Alert,
  Box,
  Button,
  Checkbox,
  Container,
  IconButton,
  List,
  ListItem,
  ListItemText,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import ThemeToggleButton from '../components/ThemeToggleButton';
import { apiFetch } from '../lib/api';

export default function HomePage({ token, user, isDark, onToggleTheme, onLogout }) {
  const [todos, setTodos] = useState([]);
  const [title, setTitle] = useState('');
  const [error, setError] = useState('');

  const fetchTodos = async () => {
    try {
      setError('');
      const data = await apiFetch('/todos', { token });
      setTodos(data);
    } catch (fetchError) {
      setError(fetchError.message);
    }
  };

  useEffect(() => {
    const loadTodos = async () => {
      try {
        setError('');
        const data = await apiFetch('/todos', { token });
        setTodos(data);
      } catch (fetchError) {
        setError(fetchError.message);
      }
    };

    loadTodos();
  }, [token]);

  const addTodo = async () => {
    if (!title.trim()) {
      return;
    }

    try {
      await apiFetch('/todos', {
        method: 'POST',
        token,
        body: { title: title.trim() },
      });
      setTitle('');
      fetchTodos();
    } catch (createError) {
      setError(createError.message);
    }
  };

  const toggleTodo = async (todo) => {
    try {
      await apiFetch(`/todos/${todo._id}`, {
        method: 'PUT',
        token,
        body: { completed: !todo.completed },
      });
      fetchTodos();
    } catch (updateError) {
      setError(updateError.message);
    }
  };

  const deleteTodo = async (id) => {
    try {
      await apiFetch(`/todos/${id}`, {
        method: 'DELETE',
        token,
      });
      fetchTodos();
    } catch (deleteError) {
      setError(deleteError.message);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: isDark
          ? 'radial-gradient(circle at top, rgba(59,130,246,0.16), transparent 28%), #0B1220'
          : 'radial-gradient(circle at top, rgba(37,99,235,0.12), transparent 26%), #F8FAFC',
        py: 6,
      }}
    >
      <ThemeToggleButton isDark={isDark} onToggle={onToggleTheme} />

      <Container maxWidth="md">
        <Box
          sx={{
            bgcolor: 'background.paper',
            border: '1px solid',
            borderColor: 'border',
            borderRadius: 4,
            p: { xs: 3, md: 4 },
            boxShadow: isDark ? '0 20px 60px rgba(0,0,0,0.38)' : '0 20px 60px rgba(15,23,42,0.08)',
          }}
        >
          <Stack
            direction={{ xs: 'column', sm: 'row' }}
            alignItems={{ xs: 'flex-start', sm: 'center' }}
            justifyContent="space-between"
            spacing={2}
          >
            <Box>
              <Typography variant="overline" sx={{ color: 'primary.main', fontWeight: 700, letterSpacing: 2 }}>
                Main page
              </Typography>
              <Typography variant="h4" sx={{ fontWeight: 800, mt: 1 }}>
                Hi {user?.name}
              </Typography>
              <Typography variant="body1" sx={{ mt: 1, color: 'text.secondary' }}>
                Your tasks stay private to your account now.
              </Typography>
            </Box>
            <Button color="inherit" variant="outlined" onClick={onLogout}>
              Log out
            </Button>
          </Stack>

          <Stack direction={{ xs: 'column', sm: 'row' }} spacing={1.5} sx={{ mt: 4 }}>
            <TextField
              value={title}
              onChange={(event) => setTitle(event.target.value)}
              placeholder="Add a task for today"
              fullWidth
            />
            <Button variant="contained" onClick={addTodo} sx={{ minWidth: { sm: 140 } }}>
              Add task
            </Button>
          </Stack>

          {error ? <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert> : null}

          <List disablePadding sx={{ mt: 3 }}>
            {todos.map((todo) => (
              <ListItem
                key={todo._id}
                disableGutters
                secondaryAction={
                  <IconButton edge="end" aria-label="delete" onClick={() => deleteTodo(todo._id)} color="error">
                    <DeleteIcon fontSize="small" />
                  </IconButton>
                }
                sx={{
                  borderBottom: '1px solid',
                  borderColor: 'divider',
                  py: 1.25,
                }}
              >
                <Checkbox checked={todo.completed} onChange={() => toggleTodo(todo)} />
                <ListItemText
                  primary={todo.title}
                  primaryTypographyProps={{
                    sx: {
                      textDecoration: todo.completed ? 'line-through' : 'none',
                      color: todo.completed ? 'text.secondary' : 'text.primary',
                    },
                  }}
                />
              </ListItem>
            ))}
          </List>
        </Box>
      </Container>
    </Box>
  );
}