import { Box, Button, Container, Grid, Stack, Typography } from '@mui/material';
import { Link as RouterLink } from 'react-router-dom';
import logo from '../assets/logo.png';

export default function AuthShell({
  title,
  description,
  eyebrow,
  cardTitle,
  cardDescription,
  actionLabel,
  actionTo,
  children,
}) {
  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: 'linear-gradient(160deg, #EFF6FF 0%, #DBEAFE 52%, #F8FAFC 100%)',
      }}
    >
      <Box
        component="header"
        sx={{
          bgcolor: 'rgba(255,255,255,0.86)',
          backdropFilter: 'blur(14px)',
          px: { xs: 3, md: 6 },
          py: 2,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          boxShadow: '0 1px 0 rgba(226,232,240,0.95)',
        }}
      >
        <Stack direction="row" spacing={1.5} alignItems="center">
          <Box
            component="img"
            src={logo}
            alt="Lanzo logo"
            sx={{ width: 36, height: 36, objectFit: 'contain' }}
          />
          <Typography
            variant="h6"
            sx={{ color: 'primary.main', fontWeight: 700, letterSpacing: '-0.3px' }}
          >
            Lanzo
          </Typography>
        </Stack>

        {actionLabel && actionTo ? (
          <Button
            component={RouterLink}
            to={actionTo}
            variant="outlined"
            sx={{
              borderColor: 'primary.main',
              color: 'primary.main',
              fontWeight: 700,
              px: 3,
              py: 1,
              borderRadius: 2,
              '&:hover': {
                borderColor: 'primary.dark',
                bgcolor: 'primary.light',
              },
            }}
          >
            {actionLabel}
          </Button>
        ) : null}
      </Box>

      <Container maxWidth="lg" sx={{ py: { xs: 5, md: 8 } }}>
        <Grid container spacing={{ xs: 4, md: 8 }} alignItems="center">
          <Grid item xs={12} md={6}>
            <Box sx={{ maxWidth: 520 }}>
              <Typography
                variant="overline"
                sx={{ color: 'primary.main', fontWeight: 700, letterSpacing: 2, fontSize: '0.75rem' }}
              >
                {eyebrow}
              </Typography>
              <Typography
                variant="h2"
                sx={{
                  color: 'text.primary',
                  fontWeight: 800,
                  lineHeight: 1.08,
                  mt: 1.5,
                  fontSize: { xs: '2.25rem', md: '3.35rem' },
                  letterSpacing: '-1.4px',
                }}
              >
                {title}
              </Typography>
              <Typography
                variant="body1"
                sx={{ mt: 2.5, color: 'text.secondary', fontSize: '1.02rem', lineHeight: 1.8 }}
              >
                {description}
              </Typography>
            </Box>
          </Grid>

          <Grid item xs={12} md={6}>
            <Box
              sx={{
                p: { xs: 3, md: 4 },
                borderRadius: 4,
                bgcolor: 'background.paper',
                border: '1px solid',
                borderColor: 'border',
                boxShadow: '0 28px 80px rgba(15,23,42,0.12)',
                maxWidth: 520,
                mx: 'auto',
              }}
            >
              <Typography variant="h5" sx={{ fontWeight: 700, color: 'text.primary' }}>
                {cardTitle}
              </Typography>
              {cardDescription ? (
                <Typography variant="body2" sx={{ mt: 1, mb: 3, color: 'text.secondary', lineHeight: 1.7 }}>
                  {cardDescription}
                </Typography>
              ) : null}
              {children}
            </Box>
          </Grid>
        </Grid>
      </Container>
    </Box>
  );
}