import { useMemo, useState } from 'react';
import {
  Alert,
  Box,
  Button,
  Stack,
  TextField,
  Typography,
} from '@mui/material';
import { Link as RouterLink, useNavigate, useSearchParams } from 'react-router-dom';
import AuthShell from '../components/AuthShell';
import { validateEmail } from '../lib/validators';

export default function LoginPage({ onLogin }) {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const defaultEmail = useMemo(() => searchParams.get('email') || '', [searchParams]);
  const [email, setEmail] = useState(defaultEmail);
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const helperMessage = searchParams.get('exists')
    ? 'Account found. Enter your password to continue.'
    : 'Use the same email you entered during sign up.';

  const handleSubmit = async (event) => {
    event.preventDefault();
    const emailIssue = validateEmail(email);

    if (emailIssue) {
      setError(emailIssue);
      return;
    }

    if (!password) {
      setError('Password is required');
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      await onLogin({ email, password });
      navigate('/app', { replace: true });
    } catch (loginError) {
      setError(loginError.message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <AuthShell
      eyebrow="Welcome back"
      title="Pick up right where your day left off."
      description="Your tasks, priorities, and progress stay in one focused workspace."
      cardTitle="Log in"
      cardDescription={helperMessage}
      actionLabel="Back to home"
      actionTo="/"
    >
      <Box component="form" onSubmit={handleSubmit}>
        <Stack spacing={2.25}>
          {error ? <Alert severity="error">{error}</Alert> : null}

          <TextField
            label="Email"
            name="email"
            type="email"
            value={email}
            onChange={(event) => setEmail(event.target.value)}
            autoComplete="username"
            fullWidth
          />

          <TextField
            label="Password"
            name="password"
            type="password"
            value={password}
            onChange={(event) => setPassword(event.target.value)}
            autoComplete="current-password"
            fullWidth
          />

          <Box sx={{ display: 'flex', justifyContent: 'flex-end' }}>
            <Button
              component={RouterLink}
              to={`/forgot-password${email ? `?email=${encodeURIComponent(email)}` : ''}`}
              size="small"
              sx={{ textTransform: 'none', fontWeight: 700 }}
            >
              Forgot password?
            </Button>
          </Box>

          <Button type="submit" variant="contained" size="large" disabled={submitting} fullWidth>
            {submitting ? 'Logging in...' : 'Log in'}
          </Button>

          <Typography variant="body2" sx={{ color: 'text.secondary', textAlign: 'center' }}>
            New here?{' '}
            <Typography
              component={RouterLink}
              to="/"
              sx={{ color: 'primary.main', fontWeight: 700, textDecoration: 'none' }}
            >
              Start with your email
            </Typography>
          </Typography>
        </Stack>
      </Box>
    </AuthShell>
  );
}