import { useMemo, useState } from 'react';
import {
  Alert,
  Box,
  Button,
  Stack,
  TextField,
} from '@mui/material';
import { useNavigate, useSearchParams } from 'react-router-dom';
import AuthShell from '../components/AuthShell';
import PasswordChecklist from '../components/PasswordChecklist';
import { apiFetch } from '../lib/api';
import { validateEmail, validatePassword } from '../lib/validators';

export default function ForgotPasswordPage({ onAuthenticated }) {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const initialEmail = useMemo(() => searchParams.get('email') || '', [searchParams]);
  const [email, setEmail] = useState(initialEmail);
  const [otp, setOtp] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [ticket, setTicket] = useState('');
  const [stage, setStage] = useState('request');
  const [error, setError] = useState('');
  const [info, setInfo] = useState('Enter your account email and we will send an OTP.');
  const [submitting, setSubmitting] = useState(false);

  const handleRequestOtp = async (event) => {
    event.preventDefault();
    const emailIssue = validateEmail(email);

    if (emailIssue) {
      setError(emailIssue);
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      await apiFetch('/auth/forgot-password', {
        method: 'POST',
        body: { email },
      });
      setStage('otp');
      setInfo('We sent a 6-digit OTP to your email.');
    } catch (requestError) {
      setError(requestError.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleVerifyOtp = async (event) => {
    event.preventDefault();

    if (!otp || otp.length !== 6) {
      setError('Enter the 6-digit OTP');
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      const data = await apiFetch('/auth/verify-otp', {
        method: 'POST',
        body: { email, otp, purpose: 'reset' },
      });
      setTicket(data.ticket);
      setStage('reset');
      setInfo('OTP verified. Set a new password.');
    } catch (verifyError) {
      setError(verifyError.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleResetPassword = async (event) => {
    event.preventDefault();
    const passwordIssue = validatePassword(password);

    if (passwordIssue) {
      setError(passwordIssue);
      return;
    }

    if (password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    try {
      setSubmitting(true);
      setError('');
      const data = await apiFetch('/auth/reset-password', {
        method: 'POST',
        body: { email, password, ticket },
      });
      onAuthenticated(data);
      navigate('/app', { replace: true });
    } catch (resetError) {
      setError(resetError.message);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <AuthShell
      eyebrow="Password recovery"
      title="Get back in without losing momentum."
      description="We verify your identity by email before letting you create a new password."
      cardTitle={
        stage === 'request'
          ? 'Forgot password'
          : stage === 'otp'
            ? 'Verify OTP'
            : 'Create a new password'
      }
      cardDescription={info}
      actionLabel="Log in"
      actionTo={email ? `/login?email=${encodeURIComponent(email)}` : '/login'}
    >
      <Box
        component="form"
        onSubmit={
          stage === 'request'
            ? handleRequestOtp
            : stage === 'otp'
              ? handleVerifyOtp
              : handleResetPassword
        }
      >
        <Stack spacing={2.25}>
          {error ? <Alert severity="error">{error}</Alert> : null}

          <TextField
            label="Email"
            name="email"
            type="email"
            value={email}
            onChange={(event) => setEmail(event.target.value)}
            autoComplete="username"
            fullWidth
            InputProps={{ readOnly: stage !== 'request' }}
          />

          {stage === 'otp' ? (
            <TextField
              label="OTP"
              value={otp}
              onChange={(event) => setOtp(event.target.value.replace(/\D/g, '').slice(0, 6))}
              inputProps={{ inputMode: 'numeric', pattern: '[0-9]*', maxLength: 6 }}
              fullWidth
            />
          ) : null}

          {stage === 'reset' ? (
            <>
              <TextField
                label="New password"
                name="newPassword"
                type="password"
                value={password}
                onChange={(event) => setPassword(event.target.value)}
                autoComplete="new-password"
                fullWidth
              />

              <PasswordChecklist password={password} />

              <TextField
                label="Confirm new password"
                name="confirmNewPassword"
                type="password"
                value={confirmPassword}
                onChange={(event) => setConfirmPassword(event.target.value)}
                autoComplete="new-password"
                fullWidth
              />
            </>
          ) : null}

          <Button type="submit" variant="contained" size="large" disabled={submitting} fullWidth>
            {stage === 'request'
              ? submitting
                ? 'Sending OTP...'
                : 'Send OTP'
              : stage === 'otp'
                ? submitting
                  ? 'Verifying...'
                  : 'Verify OTP'
                : submitting
                  ? 'Saving password...'
                  : 'Save new password'}
          </Button>
        </Stack>
      </Box>
    </AuthShell>
  );
}